import{_ as e,o as a,c as i,a4 as d}from"./chunks/framework.EG5hAXdg.js";const m=JSON.parse('{"title":"Price examples","description":"This page list examples of yearly cost for selected use cases in HUNT Cloud.","frontmatter":{"title":"Price examples","category":"HUNT Cloud","permalink":"/administer-science/prices/examples","outline":"2-3","description":"This page list examples of yearly cost for selected use cases in HUNT Cloud."},"headers":[],"relativePath":"administer-science/prices/examples.md","filePath":"administer-science/prices/examples.md"}'),s={name:"administer-science/prices/examples.md"};function o(r,t,n,l,c,p){return a(),i("div",null,[...t[0]||(t[0]=[d('<h1 id="price-examples" tabindex="-1">Price examples <a class="header-anchor" href="#price-examples" aria-label="Permalink to &quot;Price examples&quot;">​</a></h1><p><strong>We know, the complexity of flexible cloud prices is demanding. Bare with us, because the flexibility opens opportunities. Here are a few examples to give you a pricing direction.</strong></p><nav class="table-of-contents"><ul><li><a href="#individual-labs">Individual labs</a><ul><li><a href="#epidemiology">Epidemiology</a></li><li><a href="#genomics">Genomics</a></li></ul></li></ul></nav><p>For the record, all prices in the examples are listed as VAT exclusive in NOK from the <a href="/administer-science/prices/pricelist">price list</a>. The prices are provided for guidance and may contain both errors and outdated information.</p><div class="tip custom-block"><p class="custom-block-title">Estimate your specific cost</p><p>Head over to our <a href="/administer-science/prices/estimator">pricing calculator</a> to estimate the cost for your specific scientific environment, and do not hesitate to <a href="/contact">contact us</a> for assistance.</p></div><h2 id="individual-labs" tabindex="-1">Individual labs <a class="header-anchor" href="#individual-labs" aria-label="Permalink to &quot;Individual labs&quot;">​</a></h2><p>Let&#39;s start with a few examples of prices for individual labs configured for common experiments. Depending on your data space subscription and cost optimization configuration, the listed prices may be reduced.</p><h3 id="epidemiology" tabindex="-1">Epidemiology <a class="header-anchor" href="#epidemiology" aria-label="Permalink to &quot;Epidemiology&quot;">​</a></h3><p>This is the smallest lab size tailored for data analysis of structured data such as health registries and survey data that you collect.</p><table tabindex="0"><thead><tr><th>Service</th><th>Description</th><th>Type</th><th>Cost/unit</th><th>Units</th><th>Total cost</th></tr></thead><tbody><tr><td>Lab</td><td>subscription</td><td>1 year</td><td>9354</td><td>1</td><td>9354</td></tr><tr><td>Compute</td><td>default.c1</td><td>1 year</td><td>5360</td><td>1</td><td>5360</td></tr><tr><td>Store</td><td>1 terabyte</td><td>1 year</td><td>2844</td><td>1</td><td>2844</td></tr><tr><td><strong>PER YEAR</strong></td><td></td><td></td><td></td><td></td><td><strong>17558</strong></td></tr></tbody></table><p>The above example establishes your own lab in HUNT Cloud with access to commonly used tools in HUNT Workbench. Your lab holds sufficient resources for analysis for a small team. Both compute and store can easily be upgraded as your experiments grow.</p><h3 id="genomics" tabindex="-1">Genomics <a class="header-anchor" href="#genomics" aria-label="Permalink to &quot;Genomics&quot;">​</a></h3><p>Next up is a typical lab for genomics analysis. Let&#39;s assume you need a lab to store and analyze genomics data from several sources with a varied set of tools.</p><table tabindex="0"><thead><tr><th>Service</th><th>Description</th><th>Type</th><th>Cost/unit</th><th>Units</th><th>Total cost</th></tr></thead><tbody><tr><td>Lab</td><td></td><td>1 year</td><td>9354</td><td>1</td><td>9354</td></tr><tr><td>Compute</td><td>default.b5</td><td>1 year</td><td>41462</td><td>1</td><td>41462</td></tr><tr><td>Store</td><td>10 terabytes</td><td>1 year</td><td>2844</td><td>10</td><td>28440</td></tr><tr><td><strong>PER YEAR</strong></td><td></td><td></td><td></td><td></td><td><strong>79256</strong></td></tr></tbody></table><p>The above example establishes one lab, a reasonable powerful machine fit for many analysis, and storage capacity to both experiment and archive larger data sets. The cost can be reduced by for example reducing the compute size in day-to-day activities and then upgrade to larger on-demand machines in analysis intensive periods.</p>',15)])])}const u=e(s,[["render",o]]);export{m as __pageData,u as default};
